// CsqlLexerInit initializes any static state used to implement CsqlLexer. By default the
// static state used to implement the lexer is lazily initialized during the first call to
// NewCsqlLexer(). You can call this function if you wish to initialize the static state ahead
// of time.
func CsqlLexerInit() {
	staticData := &csqllexerLexerStaticData
	staticData.once.Do(csqllexerLexerInit)
}

// NewCsqlLexer produces a new lexer instance for the optional input antlr.CharStream.
func NewCsqlLexer(input antlr.CharStream) *CsqlLexer {
	CsqlLexerInit()
	l := new(CsqlLexer)
	l.BaseLexer = antlr.NewBaseLexer(input)
	staticData := &csqllexerLexerStaticData
	l.Interpreter = antlr.NewLexerATNSimulator(l, staticData.atn, staticData.decisionToDFA, staticData.predictionContextCache)
	l.channelNames = staticData.channelNames
	l.modeNames = staticData.modeNames
	l.RuleNames = staticData.ruleNames
	l.LiteralNames = staticData.literalNames
	l.SymbolicNames = staticData.symbolicNames
	l.GrammarFileName = "Csql.g4"
	// TODO: l.EOF = antlr.TokenEOF

	return l
}

